VALUES
  ('optician-moex-00909', 'optician', 'optician-moex-110-d6d7f3e6', 'sub-optician-02', NULL, 'single_choice', '基本上，紫外線也可分為三個波段，UVC（100～280nm）、UVB（280～315nm）、UVA（315～380nm）， 那一波段的紫外線一般可被大氣層中的氧、氮、臭氧層吸收？', '["UVA", "UVB", "UVC", "UVA跟UVB"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:30+00:00", "source_pdf_sha1": "faad060e3779", "answer_pdf_sha1": "2218a04d85a0", "source_family": "moex-gov-tw", "moex": {"exam_code": "110111", "c": "113", "s": "1109", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "眼鏡光學概要", "year": "110", "exam_name": "第二梯次:110年第二次專技人員高等考試中醫師考試分階段考試、營養師、社會工作師考試、110年專技人員高等考試心理師、法醫師、語言治療師、聽...", "original_question_number": 50, "answer_corrected": false, "flags": [], "slug": "optician", "db_exam_id": "optician"}'::jsonb, NULL),
  ('optician-moex-00910', 'optician', 'optician-moex-110-72ff33b8', 'sub-optician-03', NULL, 'single_choice', '有關隱形眼鏡材質運用，下列何者最不合適？', '["遠視眼常選戴用低Dk材質硬式鏡片", "圓錐角膜可以受益於較低Dk材質硬式鏡片", "無晶體症的兒童經常受益於矽水膠鏡片", "一般兒童可受益於大直徑的硬式透氣鏡片"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:31+00:00", "source_pdf_sha1": "79a1785aebea", "answer_pdf_sha1": "c0d5dd75a323", "source_family": "moex-gov-tw", "moex": {"exam_code": "110111", "c": "113", "s": "1108", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "隱形眼鏡學概要", "year": "110", "exam_name": "第二梯次:110年第二次專技人員高等考試中醫師考試分階段考試、營養師、社會工作師考試、110年專技人員高等考試心理師、法醫師、語言治療師、聽...", "original_question_number": 1, "answer_corrected": false, "flags": [], "slug": "optician", "db_exam_id": "optician"}'::jsonb, NULL),
  ('optician-moex-00911', 'optician', 'optician-moex-110-72ff33b8', 'sub-optician-03', NULL, 'single_choice', '淚膜透過表面交互作用（surfaceinteractions）方式濕潤硬式鏡片，下列那一種方式作用最強？', '["氫鍵（hydrogenbonding）", "疏水作用（hydrophobicinteraction）", "靜電作用（electrostaticinteraction）", "水化作用（hydration）"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:31+00:00", "source_pdf_sha1": "79a1785aebea", "answer_pdf_sha1": "c0d5dd75a323", "source_family": "moex-gov-tw", "moex": {"exam_code": "110111", "c": "113", "s": "1108", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "隱形眼鏡學概要", "year": "110", "exam_name": "第二梯次:110年第二次專技人員高等考試中醫師考試分階段考試、營養師、社會工作師考試、110年專技人員高等考試心理師、法醫師、語言治療師、聽...", "original_question_number": 2, "answer_corrected": false, "flags": [], "slug": "optician", "db_exam_id": "optician"}'::jsonb, NULL),
  ('optician-moex-00912', 'optician', 'optician-moex-110-72ff33b8', 'sub-optician-03', NULL, 'single_choice', '關於軟式隱形眼鏡材質離子電荷（ioniccharge），下列敘述何者錯誤？', '["帶負電荷稱為離子性材質", "非離子性材質抗沉澱性優於離子性材質", "離子性材質易吸引淚液的帶正電物質", "帶負離子電荷的材質在鹼性溶液中會導致尺寸變化甚至材料退化"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:31+00:00", "source_pdf_sha1": "79a1785aebea", "answer_pdf_sha1": "c0d5dd75a323", "source_family": "moex-gov-tw", "moex": {"exam_code": "110111", "c": "113", "s": "1108", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "隱形眼鏡學概要", "year": "110", "exam_name": "第二梯次:110年第二次專技人員高等考試中醫師考試分階段考試、營養師、社會工作師考試、110年專技人員高等考試心理師、法醫師、語言治療師、聽...", "original_question_number": 3, "answer_corrected": false, "flags": [], "slug": "optician", "db_exam_id": "optician"}'::jsonb, NULL),
  ('optician-moex-00913', 'optician', 'optician-moex-110-72ff33b8', 'sub-optician-03', NULL, 'single_choice', '有關於軟式水膠隱形眼鏡的含水量（watercontent），下列敘述何者錯誤？', '["高含水量鏡片比低含水量鏡片的彈性模量（modulusofelasticity）較低", "低含水量鏡片比高含水量鏡片的保濕性較好", "軟式水膠隱形眼鏡含水量65%的材質折射率比含水量35%的材質折射率較高", "低含水量鏡片比高含水量鏡片，較不易有沉澱物"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:31+00:00", "source_pdf_sha1": "79a1785aebea", "answer_pdf_sha1": "c0d5dd75a323", "source_family": "moex-gov-tw", "moex": {"exam_code": "110111", "c": "113", "s": "1108", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "隱形眼鏡學概要", "year": "110", "exam_name": "第二梯次:110年第二次專技人員高等考試中醫師考試分階段考試、營養師、社會工作師考試、110年專技人員高等考試心理師、法醫師、語言治療師、聽...", "original_question_number": 4, "answer_corrected": false, "flags": [], "slug": "optician", "db_exam_id": "optician"}'::jsonb, NULL),
  ('optician-moex-00914', 'optician', 'optician-moex-110-72ff33b8', 'sub-optician-03', NULL, 'single_choice', '對於硬式隱形眼鏡鏡片的敘述，下列何者錯誤？', '["周邊弧（peripheralcurve）的寬度約占鏡片周圍20～30%的面積", "協助鏡片有良好的定位是周邊弧的功用之一", "硬式隱形眼鏡除光學中心區以外的周邊，又有二個周邊的弧度，此鏡片稱為三弧（tricurve）鏡片", "有理想的鏡片定位時，最佳的軸向邊緣間隙（axialedgeclearance）大小為10～20 μm"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:31+00:00", "source_pdf_sha1": "79a1785aebea", "answer_pdf_sha1": "c0d5dd75a323", "source_family": "moex-gov-tw", "moex": {"exam_code": "110111", "c": "113", "s": "1108", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "隱形眼鏡學概要", "year": "110", "exam_name": "第二梯次:110年第二次專技人員高等考試中醫師考試分階段考試、營養師、社會工作師考試、110年專技人員高等考試心理師、法醫師、語言治療師、聽...", "original_question_number": 5, "answer_corrected": false, "flags": [], "slug": "optician", "db_exam_id": "optician"}'::jsonb, NULL),
  ('optician-moex-00915', 'optician', 'optician-moex-110-72ff33b8', 'sub-optician-03', NULL, 'single_choice', '下列何種材質，較易增加軟式隱形眼鏡一般蛋白質沉澱物量？', '["低含水量、非離子性", "低含水量、離子性", "高含水量、離子性", "高含水量、非離子性"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:31+00:00", "source_pdf_sha1": "79a1785aebea", "answer_pdf_sha1": "c0d5dd75a323", "source_family": "moex-gov-tw", "moex": {"exam_code": "110111", "c": "113", "s": "1108", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "隱形眼鏡學概要", "year": "110", "exam_name": "第二梯次:110年第二次專技人員高等考試中醫師考試分階段考試、營養師、社會工作師考試、110年專技人員高等考試心理師、法醫師、語言治療師、聽...", "original_question_number": 6, "answer_corrected": false, "flags": [], "slug": "optician", "db_exam_id": "optician"}'::jsonb, NULL),
  ('optician-moex-00916', 'optician', 'optician-moex-110-72ff33b8', 'sub-optician-03', NULL, 'single_choice', '有關水膠隱形眼鏡（hydrogelcontactlenses）材料機械性質，與配戴的舒適性、貼合度、耐久性有關，傳統 測試上會施加一變形力（deformingforce）去觀察鏡片所產生的變形量（strain），下列敘述何者錯誤？', '["剪切（shear）是一種垂直於表面的應力", "壓縮（compression）是一種施予物體縮短的壓力", "張力（tension）是一種施予物體拉長的壓力", "鏡片的變形量為施力後與原始尺寸和形狀的差異"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:31+00:00", "source_pdf_sha1": "79a1785aebea", "answer_pdf_sha1": "c0d5dd75a323", "source_family": "moex-gov-tw", "moex": {"exam_code": "110111", "c": "113", "s": "1108", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "隱形眼鏡學概要", "year": "110", "exam_name": "第二梯次:110年第二次專技人員高等考試中醫師考試分階段考試、營養師、社會工作師考試、110年專技人員高等考試心理師、法醫師、語言治療師、聽...", "original_question_number": 7, "answer_corrected": false, "flags": [], "slug": "optician", "db_exam_id": "optician"}'::jsonb, NULL),
  ('optician-moex-00917', 'optician', 'optician-moex-110-72ff33b8', 'sub-optician-03', NULL, 'single_choice', '根據美國FDA的分類將水膠隱形眼鏡依特性分成四類，下列含水量（EWC）為69%且離子含量<0.2的水 膠隱形眼鏡為那一類？', '["I類", "II類", "III類", "IV類"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:31+00:00", "source_pdf_sha1": "79a1785aebea", "answer_pdf_sha1": "c0d5dd75a323", "source_family": "moex-gov-tw", "moex": {"exam_code": "110111", "c": "113", "s": "1108", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "隱形眼鏡學概要", "year": "110", "exam_name": "第二梯次:110年第二次專技人員高等考試中醫師考試分階段考試、營養師、社會工作師考試、110年專技人員高等考試心理師、法醫師、語言治療師、聽...", "original_question_number": 8, "answer_corrected": false, "flags": [], "slug": "optician", "db_exam_id": "optician"}'::jsonb, NULL),
  ('optician-moex-00918', 'optician', 'optician-moex-110-72ff33b8', 'sub-optician-03', NULL, 'single_choice', '有關水膠隱形眼鏡的材質，下列敘述何者錯誤？', '["methylmethacrylate（MMA）是非親水性，可用於增加鏡片硬度", "polyvinylalcohol（PVA）降低淚液的表面張力，可用於增加鏡片舒適度", "methacrylicacid（MAA）是非親水性，可用於增加鏡片硬度", "polyvinylpyrrolidone（PVP）降低鏡片表面的摩擦係數，可用於增加鏡片舒適度"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:31+00:00", "source_pdf_sha1": "79a1785aebea", "answer_pdf_sha1": "c0d5dd75a323", "source_family": "moex-gov-tw", "moex": {"exam_code": "110111", "c": "113", "s": "1108", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "隱形眼鏡學概要", "year": "110", "exam_name": "第二梯次:110年第二次專技人員高等考試中醫師考試分階段考試、營養師、社會工作師考試、110年專技人員高等考試心理師、法醫師、語言治療師、聽...", "original_question_number": 9, "answer_corrected": false, "flags": [], "slug": "optician", "db_exam_id": "optician"}'::jsonb, NULL)
